/**
 * NIST SP 800-53 Rev5 Control Narrative Template Library
 * Pre-written implementation narratives for all 20 control families.
 * Templates use {{systemName}} placeholder for system-specific customization.
 */

export interface ControlTemplate {
  id: string;
  title: string;
  narrative: string;
  status: string;
}

export interface FamilyTemplates {
  family: string;
  familyName: string;
  controls: ControlTemplate[];
}

/** Substitute {{systemName}} in a narrative */
export function applyTemplate(narrative: string, systemName: string): string {
  return narrative.replace(/\{\{systemName\}\}/g, systemName || 'the information system');
}

