/** Get templates for a specific control family */
export function getTemplatesForFamily(family: string): ControlTemplate[] {
  const found = CONTROL_TEMPLATES.find((f) => f.family === family);
  return found?.controls || [];
}

/** Get a single control template by ID */
export function getTemplateById(controlId: string): ControlTemplate | undefined {
  for (const family of CONTROL_TEMPLATES) {
    const ctrl = family.controls.find((c) => c.id === controlId);
    if (ctrl) return ctrl;
  }
  return undefined;
}

/** Get all templates for a family, customized with system name */
export function getCustomizedTemplates(family: string, systemName: string): ControlTemplate[] {
  return getTemplatesForFamily(family).map((t) => ({
    ...t,
    narrative: applyTemplate(t.narrative, systemName),
  }));
}
